const HREFLANG_END = '<!-- HREFLANG:GENERATED:END -->';
const SITEMAP_START = '<!-- LOCAL-PAGES:GENERATED:START -->';
const SITEMAP_END = '<!-- LOCAL-PAGES:GENERATED:END -->';

