/* ------------------------------------------------------------------------ */
/* hreflang injection into hand-written EN pages                              */
/* ------------------------------------------------------------------------ */

function injectHreflang(html, city) {
  const indentMatch = html.match(/^([ \t]*)<link rel="canonical"/m);
  const indent = indentMatch ? indentMatch[1] : '    ';
  const block = hreflangLines(city, indent);

  const startIdx = html.indexOf(HREFLANG_START);
  if (startIdx !== -1) {
    const endIdx = html.indexOf(HREFLANG_END);
    if (endIdx === -1) throw new Error(`${city.slug}: HREFLANG start marker without end marker`);
    const before = html.slice(0, html.lastIndexOf('\n', startIdx) + 1);
    const after = html.slice(html.indexOf('\n', endIdx));
    return `${before}${block}${after}`;
  }

  const canonicalLine = html.match(/^[ \t]*<link rel="canonical"[^\n]*\n/m);
  if (!canonicalLine) throw new Error(`${city.slug}: no canonical link found to anchor hreflang block`);
  return html.replace(canonicalLine[0], `${canonicalLine[0]}${block}\n`);
}

/* ------------------------------------------------------------------------ */
/* sitemap block                                                              */
/* ------------------------------------------------------------------------ */

function sitemapEntry(loc, image, title, caption) {
  return [
    '  <url>',
    `    <loc>${loc}</loc>`,
    `    <lastmod>${LASTMOD}</lastmod>`,
    '    <changefreq>monthly</changefreq>',
    '    <priority>0.7</priority>',
    '    <image:image>',
    `      <image:loc>${SITE}${image}</image:loc>`,
    `      <image:title>${title}</image:title>`,
    `      <image:caption>${caption.replaceAll('&', '&amp;')}</image:caption>`,
    '    </image:image>',
    '  </url>'
  ].join('\n');
}

function sitemapBlock() {
  const entries = [];
  for (const city of CITY_PAGES) {
    if (city.ownsEn) {
      entries.push(sitemapEntry(enUrl(city), city.image, city.en.sitemapImageTitle, city.en.sitemapImageCaption));
    }
    entries.push(sitemapEntry(esUrl(city), city.image, city.es.sitemapImageTitle, city.es.sitemapImageCaption));
  }
  return `  ${SITEMAP_START}\n${entries.join('\n')}\n  ${SITEMAP_END}`;
}

function updateSitemap(xml) {
  const block = sitemapBlock();
  const startIdx = xml.indexOf(SITEMAP_START);
  if (startIdx !== -1) {
    const endIdx = xml.indexOf(SITEMAP_END);
    if (endIdx === -1) throw new Error('sitemap.xml: LOCAL-PAGES start marker without end marker');
    const before = xml.slice(0, xml.lastIndexOf('\n', startIdx) + 1);
    const after = xml.slice(xml.indexOf('\n', endIdx));
    return `${before}${block}${after}`;
  }
  return xml.replace(/^<\/urlset>/m, `${block}\n</urlset>`);
}

/* ------------------------------------------------------------------------ */
/* run                                                                        */
/* ------------------------------------------------------------------------ */

const outputs = [];

for (const city of CITY_PAGES) {
  if (city.ownsEn) {
    outputs.push({ rel: `service-areas/${city.slug}/index.html`, content: renderPage(city, 'en') });
  } else {
    const rel = `service-areas/${city.slug}/index.html`;
    const existing = fs.readFileSync(path.join(ROOT, rel), 'utf8');
    outputs.push({ rel, content: injectHreflang(existing, city) });
  }
  outputs.push({ rel: `es/service-areas/${city.slug}/index.html`, content: renderPage(city, 'es') });
}

outputs.push({ rel: 'sitemap.xml', content: updateSitemap(fs.readFileSync(path.join(ROOT, 'sitemap.xml'), 'utf8')) });

const drifted = [];
for (const { rel, content } of outputs) {
  const abs = path.join(ROOT, rel);
  const current = fs.existsSync(abs) ? fs.readFileSync(abs, 'utf8') : null;
  if (current === content) continue;
  drifted.push(rel);
  if (!CHECK) {
    fs.mkdirSync(path.dirname(abs), { recursive: true });
    fs.writeFileSync(abs, content);
  }
}

if (CHECK) {
  if (drifted.length) {
    console.error(`generate_local_pages --check: ${drifted.length} file(s) out of sync:`);
    for (const rel of drifted) console.error(`  - ${rel}`);
    console.error('Run: node scripts/generate_local_pages.js');
    process.exit(1);
  }
  console.log(`generate_local_pages --check: ${outputs.length} files in sync.`);
} else {
  console.log(`generate_local_pages: ${outputs.length} files managed, ${drifted.length} written.`);
  for (const rel of drifted) console.log(`  ~ ${rel}`);
}
